import{_ as a,o as i,c as o,a3 as t}from"./chunks/framework.BveOjhN0.js";const g=JSON.parse('{"title":"XiHan.Framework.Web.RealTime","description":"","frontmatter":{},"headers":[],"relativePath":"cosmos/framework/packages/web-realtime.md","filePath":"cosmos/framework/packages/web-realtime.md","lastUpdated":1783216089000}'),n={name:"cosmos/framework/packages/web-realtime.md"};function s(d,e,r,l,c,h){return i(),o("div",null,[...e[0]||(e[0]=[t(`<h1 id="xihan-framework-web-realtime" tabindex="-1">XiHan.Framework.Web.RealTime <a class="header-anchor" href="#xihan-framework-web-realtime" aria-label="Permalink to &quot;XiHan.Framework.Web.RealTime&quot;">​</a></h1><blockquote><p>实时通信：基于 SignalR 的服务端集成，提供 Hub 基类、连接管理、按用户/组/全体的实时通知服务与统一 JSON 序列化。</p></blockquote><ul><li><strong>NuGet</strong>：<code>XiHan.Framework.Web.RealTime</code></li><li><strong>模块类</strong>：<code>XiHanWebRealTimeModule</code></li><li><strong>所在层</strong>：Web 层</li></ul><h2 id="这是什么" tabindex="-1">这是什么 <a class="header-anchor" href="#这是什么" aria-label="Permalink to &quot;这是什么&quot;">​</a></h2><p>XiHan.Framework.Web.RealTime 把 ASP.NET Core SignalR 接入框架，用于服务器主动向客户端推送消息（通知、聊天、进度、在线状态等）。它提供一个 Hub 基类 <code>XiHanHub</code>（自动在连接/断开时维护用户与连接的映射）、一个连接管理器 <code>IConnectionManager</code>、一个泛型实时通知服务 <code>IRealtimeNotificationService&lt;THub&gt;</code>（支持发给单个用户、用户列表、指定组或全体），并统一配置 SignalR 的 JSON 协议与超时/保活等选项。</p><h2 id="何时使用" tabindex="-1">何时使用 <a class="header-anchor" href="#何时使用" aria-label="Permalink to &quot;何时使用&quot;">​</a></h2><ul><li>需要服务端向前端<strong>主动推送</strong>：站内通知、消息中心、聊天、任务进度、实时状态。</li><li>需要按「用户 / 用户列表 / 组 / 全体」定向推送，并管理用户与连接的映射关系。</li><li>需要在 SignalR 场景下用 JWT 鉴权（token 经 query string 的 <code>access_token</code> 传入，由 Web.Api 侧支持）。</li></ul><h2 id="安装" tabindex="-1">安装 <a class="header-anchor" href="#安装" aria-label="Permalink to &quot;安装&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> package</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> XiHan.Framework.Web.RealTime</span></span></code></pre></div><h2 id="启用" tabindex="-1">启用 <a class="header-anchor" href="#启用" aria-label="Permalink to &quot;启用&quot;">​</a></h2><div class="language-csharp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">DependsOn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">typeof</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">XiHanWebRealTimeModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">))]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">public</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> class</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> MyModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> : </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">XiHanModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { }</span></span></code></pre></div><p>模块在 <code>ConfigureServices</code> 中调用 <code>AddXiHanSignalRWithJson(config)</code>，注册 SignalR、连接管理器、用户 ID 提供器与实时通知服务，并从 <code>XiHan:Web:RealTime:SignalR</code> 绑定选项。</p><h2 id="核心能力" tabindex="-1">核心能力 <a class="header-anchor" href="#核心能力" aria-label="Permalink to &quot;核心能力&quot;">​</a></h2><ul><li><strong>Hub 基类</strong>：<code>XiHanHub</code> 在 <code>OnConnectedAsync</code>/<code>OnDisconnectedAsync</code> 自动登记/注销用户与连接，暴露 <code>ConnectionId</code>/<code>UserId</code>/<code>UserName</code>。</li><li><strong>连接管理</strong>：<code>IConnectionManager</code> 维护用户 ID 到连接 ID 的映射；<code>IXiHanUserIdProvider</code> 提供 SignalR 用户标识。</li><li><strong>实时通知服务</strong>：<code>IRealtimeNotificationService&lt;THub&gt;</code> 提供 <code>SendToUserAsync</code> / <code>SendToUsersAsync</code> / <code>SendToGroupAsync</code> / <code>SendToAllAsync</code> 及分组增删。</li><li><strong>JSON 协议配置</strong>：<code>AddJsonProtocol</code> 设定 <code>PayloadSerializerOptions</code> 为 CamelCase 命名、非缩进输出。</li><li><strong>Hub 选项桥接</strong>：把 <code>XiHanSignalROptions</code>（保活间隔、客户端超时、握手超时、最大消息大小、并发调用数等）映射到 SignalR <code>HubOptions</code>。</li><li><strong>鉴权与异常过滤</strong>：<code>AuthorizeHubAttribute</code> 与 <code>HubExceptionFilter</code> 支持 Hub 授权与异常处理。</li></ul><h2 id="序列化约定-重要" tabindex="-1">序列化约定（重要） <a class="header-anchor" href="#序列化约定-重要" aria-label="Permalink to &quot;序列化约定（重要）&quot;">​</a></h2><p>SignalR 的 JSON 协议仅配置了 CamelCase 命名，<strong>未注册</strong> <code>long → string</code>、枚举等自动转换器。因此推送的载荷需在<strong>应用侧手动投影</strong>为客户端可安全消费的形状（例如把 <code>long</code> ID 显式转成 <code>string</code>），Hub 方法参数也应以 <code>string</code> 接收，避免 JS 端大整数精度丢失与枚举歧义。</p><h2 id="主要类型" tabindex="-1">主要类型 <a class="header-anchor" href="#主要类型" aria-label="Permalink to &quot;主要类型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>XiHanHub</code> / <code>IXiHanHub</code></td><td>Hub 基类与接口，自动维护连接映射</td></tr><tr><td><code>IConnectionManager</code> / <code>ConnectionManager</code></td><td>用户与连接映射管理</td></tr><tr><td><code>IRealtimeNotificationService&lt;THub&gt;</code></td><td>泛型实时通知服务（用户/列表/组/全体推送）</td></tr><tr><td><code>IXiHanUserIdProvider</code> / <code>XiHanUserIdProvider</code></td><td>SignalR 用户标识提供器</td></tr><tr><td><code>XiHanSignalROptions</code></td><td>SignalR 选项（<code>XiHan:Web:RealTime:SignalR</code>）</td></tr><tr><td><code>AuthorizeHubAttribute</code> / <code>HubExceptionFilter</code></td><td>Hub 授权特性与异常过滤器</td></tr><tr><td><code>NotificationHub</code> / <code>NotificationMessage</code></td><td>内置通知 Hub 与消息模型</td></tr></tbody></table><h2 id="依赖模块" tabindex="-1">依赖模块 <a class="header-anchor" href="#依赖模块" aria-label="Permalink to &quot;依赖模块&quot;">​</a></h2><ul><li>内部依赖：<a href="./web-core">XiHan.Framework.Web.Core</a>、<a href="./authentication">XiHan.Framework.Authentication</a>。</li><li>第三方核心：ASP.NET Core 内置 SignalR（<code>Microsoft.AspNetCore.SignalR</code>）。</li></ul><h2 id="相关模块" tabindex="-1">相关模块 <a class="header-anchor" href="#相关模块" aria-label="Permalink to &quot;相关模块&quot;">​</a></h2><ul><li><a href="./web-api">XiHan.Framework.Web.Api</a> — 提供 JWT 认证并支持从 query string 的 <code>access_token</code> 取 token（SignalR 场景）。</li></ul>`,22)])])}const k=a(n,[["render",s]]);export{g as __pageData,k as default};
